{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class TrailingCommaOnDeclarationSiteRuleEmptyEnumTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                RuleProvider { WrappingRule() },
                RuleProvider { IndentationRule() },
            ),
        )

    @Test
    fun `Given an empty enum class then it should not crash`() {
        val code =
            """
            enum class Test
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an empty enum class with body then it should not crash`() {
        val code =
            """
            enum class Test {}
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an enum class with only a semicolon then it should not crash`() {
        val code =
            """
            enum class Test {
                ;
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an enum class with entries then it should still work`() {
        val code =
            """
            enum class Shape {
                SQUARE,
                TRIANGLE
            }
            """.trimIndent()
        val formattedCode =
            """
            enum class Shape {
                SQUARE,
                TRIANGLE,
            }
            """.trimIndent()
        trailingCommaOnDeclarationSiteRuleAssertThat(code)
            .withEditorConfigOverride(TrailingCommaOnDeclarationSiteRule.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY to true)
            .hasLintViolation(3, 13, "Missing trailing comma before \"}\"")
            .isFormattedAs(formattedCode)
    }
}
